class Solution:
    def cherryPickup(self, grid):
        rows, cols = len(grid), len(grid[0])
        INF = float('-inf')
        # dp[c1][c2] = best cherries when robots are at columns c1 and c2 after current row
        dp = [[INF] * cols for _ in range(cols)]
        dp[0][cols - 1] = grid[0][0] + (grid[0][cols - 1] if cols > 1 else 0)
        for r in range(1, rows):
            ndp = [[INF] * cols for _ in range(cols)]
            for c1 in range(cols):
                for c2 in range(cols):
                    if dp[c1][c2] == INF:
                        continue
                    for dc1 in (-1, 0, 1):
                        for dc2 in (-1, 0, 1):
                            nc1, nc2 = c1 + dc1, c2 + dc2
                            if 0 <= nc1 < cols and 0 <= nc2 < cols:
                                cherries = grid[r][nc1] + (grid[r][nc2] if nc1 != nc2 else 0)
                                ndp[nc1][nc2] = max(ndp[nc1][nc2], dp[c1][c2] + cherries)
            dp = ndp
        return max(dp[c1][c2] for c1 in range(cols) for c2 in range(cols) if dp[c1][c2] != INF)

