var cherryPickup = function(grid) {
    const rows = grid.length, cols = grid[0].length;
    const INF = -Infinity;
    let dp = Array.from({length: cols}, () => new Array(cols).fill(INF));
    dp[0][cols - 1] = grid[0][0] + (cols > 1 ? grid[0][cols - 1] : 0);
    for (let r = 1; r < rows; r++) {
        const ndp = Array.from({length: cols}, () => new Array(cols).fill(INF));
        for (let c1 = 0; c1 < cols; c1++) {
            for (let c2 = 0; c2 < cols; c2++) {
                if (dp[c1][c2] === INF) continue;
                for (let dc1 = -1; dc1 <= 1; dc1++) {
                    for (let dc2 = -1; dc2 <= 1; dc2++) {
                        const nc1 = c1 + dc1, nc2 = c2 + dc2;
                        if (nc1 >= 0 && nc1 < cols && nc2 >= 0 && nc2 < cols) {
                            const cherries = grid[r][nc1] + (nc1 !== nc2 ? grid[r][nc2] : 0);
                            ndp[nc1][nc2] = Math.max(ndp[nc1][nc2], dp[c1][c2] + cherries);
                        }
                    }
                }
            }
        }
        dp = ndp;
    }
    let ans = 0;
    for (let c1 = 0; c1 < cols; c1++)
        for (let c2 = 0; c2 < cols; c2++)
            if (dp[c1][c2] !== INF) ans = Math.max(ans, dp[c1][c2]);
    return ans;
};
